      {
        "segment": "Introduction & Hook",
        "minutes": 5,
        "purpose": "Engage students with real-life analogy"
      },
      {
        "segment": "Definition & Examples",
        "minutes": 10,
        "purpose": "Establish core concept"
      },
      {
        "segment": "Degree & Classification",
        "minutes": 15,
        "purpose": "Apply concept to categorize expressions"
      },
      {
        "segment": "Assessment & Recap",
        "minutes": 10,
        "purpose": "Check understanding and summarize"
      }
    ],
    "sessionSummary": [
      "Polynomials are algebraic expressions with non-negative integer powers.",
      "Degree determines the name (Linear, Quadratic, Cubic)."
    ],
    "endOfClassRecap": [
      {
        "prompt": "A polynomial cannot have variables with ________ exponents.",
        "expectedAnswer": "negative or fractional"
      },
      {
        "prompt": "The degree of the constant 5 is ________. ",
